## Full File Contents

### 1. `src/index.js`

```javascript
'use strict';

// Ensure files written to vault/quartz-output are world-readable (nginx reads them)
process.umask(0o022);

const fs = require('fs-extra');
const path = require('path');
const chokidar = require('chokidar');
const logger = require('./logger');
const { scheduleRebuild, runBuild } = require('./quartz-builder');

const VAULT_PATH    = process.env.VAULT_PATH    || '/vault';
const QUARTZ_OUTPUT = process.env.QUARTZ_OUTPUT || '/quartz-output';
const QUARTZ_SRC    = '/quartz-src';

function configureQuartz() {
  const configPath = path.join(QUARTZ_SRC, 'quartz.config.ts');
  if (!fs.existsSync(configPath)) {
    logger.warn('quartz.config.ts not found — skipping baseUrl config');
    return;
  }
  let config = fs.readFileSync(configPath, 'utf8');
  const domain = process.env.DOMAIN_NAME || 'localhost';
  config = config.replace(
    /baseUrl:\s*["'][^"']*["']/,
    `baseUrl: "notes.${domain}"`
  );
  // Ensure .obsidian is ignored
  if (!config.includes('.obsidian')) {
    config = config.replace(
      /ignorePatterns:\s*\[/,
      'ignorePatterns: [".obsidian", "tasks/pending", "tasks/done", '
    );
  }
  fs.writeFileSync(configPath, config, 'utf8');
  logger.info('quartz.config.ts updated');
}

async function main() {
  logger.info('obsidian-bridge starting');

  configureQuartz();

  await fs.ensureDir(VAULT_PATH);
  await fs.ensureDir(QUARTZ_OUTPUT);

  // Initial build from whatever is already in the vault
  runBuild(VAULT_PATH, QUARTZ_OUTPUT);

  const watcher = chokidar.watch(VAULT_PATH, {
    ignored: /(^|[/\\])\.|tasks\/(pending|done)/,
    persistent: true,
    ignoreInitial: true,
    usePolling: true,
    interval: 5000,
    awaitWriteFinish: { stabilityThreshold: 3000, pollInterval: 1000 },
  });

  watcher.on('all', (event, filePath) => {
    if (!filePath.endsWith('.md')) return;
    scheduleRebuild(VAULT_PATH, QUARTZ_OUTPUT);
  });

  logger.info(`Watching ${VAULT_PATH} for changes`);
}

main().catch(err => {
  logger.error('Fatal error', err.message);
  process.exit(1);
});
```

### 2. `src/quartz-builder.js`

```javascript
'use strict';

const { execSync } = require('child_process');
const path = require('path');
const fs = require('fs-extra');
const logger = require('./logger');

const QUARTZ_SRC = '/quartz-src';
const DEBOUNCE_MS = 3000;

let timer = null;

function scheduleRebuild(vaultPath, quartzOutput) {
  if (timer) clearTimeout(timer);
  timer = setTimeout(() => {
    timer = null;
    runBuild(vaultPath, quartzOutput);
  }, DEBOUNCE_MS);
}

function getPublishedTopics(vaultPath) {
  const researchDir = path.join(vaultPath, 'research');
  if (!fs.existsSync(researchDir)) return [];
  const entries = fs.readdirSync(researchDir, { withFileTypes: true });
  const published = [];
  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const indexPath = path.join(researchDir, entry.name, 'index.md');
    if (!fs.existsSync(indexPath)) continue;
    const content = fs.readFileSync(indexPath, 'utf8');
    const match = content.match(/^publish:\s*(true|false)/m);
    if (match && match[1] === 'true') published.push(entry.name);
  }
  return published;
}

function runBuild(vaultPath, quartzOutput) {
  try {
    const topics = getPublishedTopics(vaultPath);
    if (topics.length === 0) {
      logger.warn('No published topics (publish: true) found — skipping build');
      return;
    }
    logger.info(`Publishing ${topics.length} topic(s): ${topics.join(', ')}`);

    const includes = topics.map(t => `--include='/${t}/***'`).join(' ');
    logger.info('Syncing published topics → quartz content dir');
    execSync(
      `rsync -a --delete ${includes} --exclude='*' ${vaultPath}/research/ ${QUARTZ_SRC}/content/`,
      { stdio: 'inherit' }
    );

    // Generate a root index so Quartz produces index.html at the site root
    const topicLinks = topics.map(t => `- [[${t}/index|${t.replace(/-/g, ' ')}]]`).join('\n');
    fs.outputFileSync(
      path.join(QUARTZ_SRC, 'content', 'index.md'),
      `---\ntitle: Research\n---\n\n# Research\n\n${topicLinks}\n`
    );

    logger.info('Running quartz build');
    execSync(`npx quartz build --output ${quartzOutput}`, {
      cwd: QUARTZ_SRC,
      stdio: 'inherit',
    });

    // NFS ACLs strip world-readable bits; restore them so nginx can serve the files
    execSync(`chmod -R o+r ${quartzOutput}`, { stdio: 'inherit' });
    execSync(`find ${quartzOutput} -type d -exec chmod o+x {} +`, { stdio: 'inherit' });

    fs.outputFileSync(path.join(quartzOutput, '.last-built'), new Date().toISOString());
    logger.info('Quartz build complete');
  } catch (err) {
    logger.error('Quartz build failed', err.message);
  }
}

module.exports = { scheduleRebuild, runBuild };
```

### 3. `Dockerfile`

```dockerfile
FROM node:20-alpine
RUN apk add --no-cache git rsync

# Bake Quartz in at build time (pinned version, no internet needed at runtime)
RUN git clone --depth 1 --branch v4.4.0 https://github.com/jackyzha0/quartz.git /quartz-src \
    && cd /quartz-src && npm ci \
    && chown -R node:node /quartz-src

WORKDIR /app
COPY package.json ./
RUN npm install --production
COPY src/ ./src/

CMD ["node", "src/index.js"]
```

### 4. `package.json`

```json
{
  "name": "obsidian-bridge",
  "version": "1.0.1",
  "description": "Watches NFS vault for changes and builds Quartz static site",
  "main": "src/index.js",
  "dependencies": {
    "chokidar": "^3.6.0",
    "fs-extra": "^11.2.0"
  }
}
```

### 5. `src/logger.js`

```javascript
'use strict';

function log(level, msg, ...args) {
  const ts = new Date().toISOString();
  const extra = args.length ? ' ' + args.map(a => JSON.stringify(a)).join(' ') : '';
  console.log(`[${ts}] [${level.toUpperCase()}] ${msg}${extra}`);
}

module.exports = {
  info:  (msg, ...a) => log('info',  msg, ...a),
  warn:  (msg, ...a) => log('warn',  msg, ...a),
  error: (msg, ...a) => log('error', msg, ...a),
  debug: (msg, ...a) => log('debug', msg, ...a),
};
```

### 6. `nginx.conf`

```nginx
server {
    listen 8080;
    root /usr/share/nginx/html;
    index index.html;
    absolute_redirect off;

    location / {
        try_files $uri $uri.html $uri/index.html /404.html =404;
    }

    location ~* \.(js|css|png|jpg|svg|woff2)$ {
        expires 7d;
        add_header Cache-Control "public, immutable";
    }
}
```

---

## Key Findings

### Build Command
- **Build command**: `npx quartz build --output ${quartzOutput}` (line 61 of quartz-builder.js)
- Executes in the `/quartz-src` directory
- Default output: `/quartz-output`

### Quartz Source Location
- **Baked into the Docker image** at build time (Dockerfile line 5)
- Cloned from `https://github.com/jackyzha0/quartz.git` at tag `v4.4.0`
- Stored at `/quartz-src` in the container
- The `quartz.config.ts` is runtime-configured by `index.js` (configureQuartz function) to set the baseUrl based on DOMAIN_NAME env var

### Output Structure
- Quartz outputs to `/quartz-output` (configurable via QUARTZ_OUTPUT env var)
- Contains `.last-built` file with ISO timestamp
- Final structure appears to be HTML files with Quartz's default structure (topic folders contain HTML files)

### Post-Build Processing Already Present
Yes! The quartz-builder.js includes these post-build steps (lines 66-68):
1. **Permission fix for NFS**: `chmod -R o+r ${quartzOutput}` - makes all files world-readable so nginx can serve them
2. **Directory executable bit fix**: `find ${quartzOutput} -type d -exec chmod o+x {} +` - makes directories traversable
3. **Timestamp file**: Creates `.last-built` with current timestamp

The build is triggered by file changes in `/vault` using chokidar with a 3-second debounce, and only publishes topics in `vault/research/*/` where the `index.md` has `publish: true` at the top.

