    const src = $(el).attr('src');
    if (!src || src.startsWith('http://') || src.startsWith('https://')) return;
    if (src.startsWith('../')) $(el).attr('src', stripParent(src));
    else if (src.startsWith('/static/')) $(el).attr('src', src.slice(1)); // /static/X → static/X
