    if (href === relPrefix || href.startsWith(`${relPrefix}/`) || href.startsWith(`${relPrefix}#`) ||
        href === absPrefix || href.startsWith(`${absPrefix}/`) || href.startsWith(`${absPrefix}#`)) {
