'use strict';

const http = require('http');
const path = require('path');
const fs = require('fs-extra');
const os = require('os');

// Mock buildTopicExport so the HTTP tests don't need a real Quartz output.
// The mock writes a minimal valid response so the server can complete normally.
jest.mock('../../services/obsidian-bridge/src/export-builder', () => ({
  buildTopicExport: jest.fn((quartzOutput, slug, res) => {
    return new Promise((resolve) => {
      res.writeHead(200, { 'Content-Type': 'application/zip' });
      res.end('ZIP_STUB');
      resolve();
    });
  }),
}));

const { createExportServer } = require('../../services/obsidian-bridge/src/http-server');
const { buildTopicExport } = require('../../services/obsidian-bridge/src/export-builder');

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function request(server, method, urlPath) {
  return new Promise((resolve, reject) => {
    const addr = server.address();
    const req = http.request(
      { host: '127.0.0.1', port: addr.port, method, path: urlPath },
      (res) => {
        const chunks = [];
        res.on('data', c => chunks.push(c));
        res.on('end', () => resolve({
          status: res.statusCode,
          body: Buffer.concat(chunks).toString(),
        }));
      }
    );
    req.on('error', reject);
    req.end();
  });
}

// ---------------------------------------------------------------------------
// Fixture vault + quartz output
// ---------------------------------------------------------------------------

let tmpDir, vaultPath, quartzOutput, server;

beforeAll(() => {
  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rockybot-http-'));
  vaultPath = path.join(tmpDir, 'vault');
  quartzOutput = path.join(tmpDir, 'quartz-output');

  // Published topic
  const pubDir = path.join(vaultPath, 'research', 'valid-topic');
  fs.mkdirpSync(pubDir);
  fs.writeFileSync(path.join(pubDir, 'index.md'), '---\npublish: true\n---\n');

  // Unpublished topic
  const draftDir = path.join(vaultPath, 'research', 'draft-topic');
  fs.mkdirpSync(draftDir);
  fs.writeFileSync(path.join(draftDir, 'index.md'), '---\npublish: false\n---\n');

  // Quartz output exists for valid-topic (but not draft-topic)
  fs.mkdirpSync(path.join(quartzOutput, 'valid-topic'));

  server = createExportServer(0, quartzOutput, vaultPath); // port 0 = random
});

afterAll((done) => {
  server.close(() => {
    fs.removeSync(tmpDir);
    done();
  });
});

beforeEach(() => jest.clearAllMocks());

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('http-server: routing', () => {
  it('GET /export/valid-topic → 200 and calls buildTopicExport', async () => {
    const res = await request(server, 'GET', '/export/valid-topic');
    expect(res.status).toBe(200);
    expect(buildTopicExport).toHaveBeenCalledWith(
      quartzOutput, 'valid-topic', expect.anything()
    );
  });

  it('GET / → 404', async () => {
    const res = await request(server, 'GET', '/');
    expect(res.status).toBe(404);
  });

  it('GET /export/ (no slug) → 404', async () => {
    const res = await request(server, 'GET', '/export/');
    expect(res.status).toBe(404);
  });

  it('POST /export/valid-topic → 405', async () => {
    const res = await request(server, 'POST', '/export/valid-topic');
    expect(res.status).toBe(405);
  });
});

describe('http-server: slug format gate', () => {
  it('rejects path traversal: /export/../etc/passwd → 404', async () => {
    const res = await request(server, 'GET', '/export/../etc/passwd');
    expect(res.status).toBe(404);
    expect(buildTopicExport).not.toHaveBeenCalled();
  });

  it('rejects uppercase slug: /export/UPPERCASE → 404', async () => {
    const res = await request(server, 'GET', '/export/UPPERCASE');
    expect(res.status).toBe(404);
    expect(buildTopicExport).not.toHaveBeenCalled();
  });

  it('rejects slug with spaces or special chars → 404', async () => {
    const res = await request(server, 'GET', '/export/my%20topic');
    expect(res.status).toBe(404);
    expect(buildTopicExport).not.toHaveBeenCalled();
  });

  it('rejects slug with underscore → 404', async () => {
    const res = await request(server, 'GET', '/export/my_topic');
    expect(res.status).toBe(404);
    expect(buildTopicExport).not.toHaveBeenCalled();
  });
});

describe('http-server: publish whitelist gate', () => {
  it('rejects unpublished topic → 404', async () => {
    const res = await request(server, 'GET', '/export/draft-topic');
    expect(res.status).toBe(404);
    expect(buildTopicExport).not.toHaveBeenCalled();
  });

  it('rejects topic not in vault at all → 404', async () => {
    const res = await request(server, 'GET', '/export/nonexistent-topic');
    expect(res.status).toBe(404);
    expect(buildTopicExport).not.toHaveBeenCalled();
  });
});

describe('http-server: quartz output existence gate', () => {
  it('returns 503 when topic is published but quartz output missing', async () => {
    // valid-topic IS published but we temporarily remove its quartz dir
    const qDir = path.join(quartzOutput, 'valid-topic');
    fs.removeSync(qDir);
    try {
      const res = await request(server, 'GET', '/export/valid-topic');
      expect(res.status).toBe(503);
      expect(buildTopicExport).not.toHaveBeenCalled();
    } finally {
      fs.mkdirpSync(qDir); // restore for other tests
    }
  });
});

describe('http-server: concurrency guard', () => {
  it('returns 429 on concurrent request for same slug', async () => {
    // Make buildTopicExport hang until we release it
    let releaseExport;
    buildTopicExport.mockImplementationOnce((_, __, res) => new Promise((resolve) => {
      releaseExport = () => { res.end(); resolve(); };
    }));

    // Fire first request (will hang)
    const first = request(server, 'GET', '/export/valid-topic');

    // Give the server a tick to register the in-progress lock
    await new Promise(r => setTimeout(r, 20));

    // Second request should be rejected
    const second = await request(server, 'GET', '/export/valid-topic');
    expect(second.status).toBe(429);

    // Release the first
    releaseExport();
    const firstRes = await first;
    expect(firstRes.status).toBe(200);
  });
});

'use strict';

const path = require('path');
const fs = require('fs-extra');
const os = require('os');
const { getPublishedTopics } = require('../../services/obsidian-bridge/src/quartz-builder');

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeVault(tmpDir, topics) {
  // topics: [{ name, publish, hasIndex }]
  for (const t of topics) {
    const dir = path.join(tmpDir, 'research', t.name);
    fs.mkdirpSync(dir);
    if (t.hasIndex !== false) {
      const frontmatter = t.publish !== undefined
        ? `---\npublish: ${t.publish}\n---\n`
        : `---\ntitle: no publish field\n---\n`;
      fs.writeFileSync(path.join(dir, 'index.md'), frontmatter);
    }
  }
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('getPublishedTopics', () => {
  let tmpDir;

  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'rockybot-vault-'));
  });

  afterEach(() => {
    fs.removeSync(tmpDir);
  });

  it('returns empty array when research/ directory does not exist', () => {
    expect(getPublishedTopics(tmpDir)).toEqual([]);
  });

  it('returns empty array when research/ exists but has no topics', () => {
    fs.mkdirpSync(path.join(tmpDir, 'research'));
    expect(getPublishedTopics(tmpDir)).toEqual([]);
  });

  it('returns topic with publish: true', () => {
    makeVault(tmpDir, [{ name: 'solar-california', publish: true }]);
    expect(getPublishedTopics(tmpDir)).toEqual(['solar-california']);
  });

  it('excludes topic with publish: false', () => {
    makeVault(tmpDir, [{ name: 'draft-topic', publish: false }]);
    expect(getPublishedTopics(tmpDir)).toEqual([]);
  });

  it('excludes topic with no publish field', () => {
    makeVault(tmpDir, [{ name: 'no-field-topic', publish: undefined }]);
    expect(getPublishedTopics(tmpDir)).toEqual([]);
  });

  it('excludes directory with no index.md', () => {
    makeVault(tmpDir, [{ name: 'no-index', publish: true, hasIndex: false }]);
    expect(getPublishedTopics(tmpDir)).toEqual([]);
  });

  it('ignores files in research/ root (only directories)', () => {
    fs.mkdirpSync(path.join(tmpDir, 'research'));
    fs.writeFileSync(path.join(tmpDir, 'research', 'stray-file.md'), '---\npublish: true\n---\n');
    expect(getPublishedTopics(tmpDir)).toEqual([]);
  });

  it('returns multiple published topics, excludes unpublished', () => {
    makeVault(tmpDir, [
      { name: 'topic-a', publish: true },
      { name: 'topic-b', publish: false },
      { name: 'topic-c', publish: true },
    ]);
    const result = getPublishedTopics(tmpDir);
    expect(result).toContain('topic-a');
    expect(result).toContain('topic-c');
    expect(result).not.toContain('topic-b');
    expect(result).toHaveLength(2);
  });

  it('slug is the directory name, not the title from frontmatter', () => {
    fs.mkdirpSync(path.join(tmpDir, 'research', 'my-cool-topic'));
    fs.writeFileSync(
      path.join(tmpDir, 'research', 'my-cool-topic', 'index.md'),
      '---\ntitle: My Cool Topic\npublish: true\n---\n'
    );
    expect(getPublishedTopics(tmpDir)).toEqual(['my-cool-topic']);
  });
});

'use strict';

const path = require('path');
const fs = require('fs');
const os = require('os');
const { execSync } = require('child_process');
const { PassThrough } = require('stream');
const cheerio = require('../../services/obsidian-bridge/node_modules/cheerio');
const { rewriteHtml, buildTopicExport } = require('../../services/obsidian-bridge/src/export-builder');

const FIXTURE_QUARTZ = path.join(__dirname, '../fixtures/test-quartz-output');
const TOPIC = 'my-topic';

// ---------------------------------------------------------------------------
// rewriteHtml — direct tests (no ZIP involved)
// ---------------------------------------------------------------------------

describe('rewriteHtml', () => {
  let $;
  beforeAll(() => {
    const html = fs.readFileSync(
      path.join(FIXTURE_QUARTZ, TOPIC, 'index.html'), 'utf8'
    );
    $ = cheerio.load(rewriteHtml(html, TOPIC), { decodeEntities: false });
  });

  describe('element removal', () => {
    it('removes <base> tag', () => expect($('base')).toHaveLength(0));
    it('removes all <script> tags', () => expect($('script')).toHaveLength(0));
    it('removes <link rel="modulepreload">', () => expect($('link[rel="modulepreload"]')).toHaveLength(0));
    it('removes .explorer.desktop-only', () => expect($('.explorer.desktop-only')).toHaveLength(0));
    it('removes .search', () => expect($('.search')).toHaveLength(0));
    it('removes .graph-outer', () => expect($('.graph-outer')).toHaveLength(0));
    it('removes .backlinks', () => expect($('.backlinks')).toHaveLength(0));
  });

  describe('link[href] path rewriting', () => {
    it('strips ../ from stylesheet: ../index.css → index.css', () => {
      expect($('link[rel="stylesheet"]').attr('href')).toBe('index.css');
    });
    it('strips ../ from icon: ../static/icon.png → static/icon.png', () => {
      expect($('link[rel="icon"]').attr('href')).toBe('static/icon.png');
    });
  });

  describe('img[src] path rewriting', () => {
    it('strips ../ from img src: ../static/icon.png → static/icon.png', () => {
      expect($('#content img').attr('src')).toBe('static/icon.png');
    });
  });

  describe('within-topic anchor rewriting', () => {
    it('../my-topic/sub-page → ./sub-page.html', () => {
      expect($('#content a[href="./sub-page.html"]')).toHaveLength(1);
    });
    it('../my-topic/ (root) → ./index.html', () => {
      expect($('#content a[href="./index.html"]').length).toBeGreaterThanOrEqual(1);
    });
    it('../my-topic (no slash) → ./index.html', () => {
      // both ../my-topic/ and ../my-topic map to ./index.html
      const count = $('a[href="./index.html"]').length;
      expect(count).toBeGreaterThanOrEqual(1);
    });
    it('../my-topic/sub-page#section → ./sub-page.html#section', () => {
      expect($('#content a[href="./sub-page.html#section"]')).toHaveLength(1);
    });
  });

  describe('cross-topic / external link handling', () => {
    it('neuters ../other-topic/page (removes href, adds tooltip class)', () => {
      const neutered = $('#content .export-external-link');
      expect(neutered.length).toBeGreaterThan(0);
      neutered.each((_, el) => expect($(el).attr('href')).toBeUndefined());
    });
    it('neuters ../research/my-topic/sub-page (vault-absolute path)', () => {
      // All neutered links have no href
      const allLinks = $('#content a');
      const withHref = allLinks.filter((_, el) => !!$(el).attr('href'));
      // None of the neutered ones should have href
      withHref.each((_, el) => {
        expect($(el).attr('href')).not.toMatch(/^\.\.\/research\//);
      });
    });
    it('leaves https:// links unchanged', () => {
      expect($('a[href="https://example.com"]')).toHaveLength(1);
    });
    it('leaves #heading anchor-only links unchanged', () => {
      expect($('a[href="#heading"]')).toHaveLength(1);
    });
    it('neuters "." (site root) link', () => {
      expect($('a[href="."]')).toHaveLength(0);
    });
  });
});

// ---------------------------------------------------------------------------
// buildTopicExport — ZIP structure tests
// ---------------------------------------------------------------------------

function buildZip(quartzOutput, topicSlug) {
  return new Promise((resolve, reject) => {
    const res = new PassThrough();
    res.setHeader = () => {};
    const chunks = [];
    res.on('data', c => chunks.push(c));
    res.on('error', reject);
    buildTopicExport(quartzOutput, topicSlug, res).then(() => {
      resolve(Buffer.concat(chunks));
    }).catch(reject);
  });
}

describe('buildTopicExport ZIP structure', () => {
  let tmpZip;
  let listing;

  beforeAll(async () => {
    const buf = await buildZip(FIXTURE_QUARTZ, TOPIC);
    tmpZip = path.join(os.tmpdir(), `rockybot-test-${Date.now()}.zip`);
    fs.writeFileSync(tmpZip, buf);
    listing = execSync(`unzip -l "${tmpZip}"`).toString();
  });

  afterAll(() => {
    try { fs.unlinkSync(tmpZip); } catch (_) {}
  });

  it('contains index.html at ZIP root', () => expect(listing).toContain('index.html'));
  it('contains sub-page.html at ZIP root', () => expect(listing).toContain('sub-page.html'));
  it('contains index.css at ZIP root', () => expect(listing).toContain('index.css'));
  it('contains static/icon.png', () => expect(listing).toContain('static/icon.png'));
  it('does not contain topic subdir prefix (e.g. my-topic/index.html)', () =>
    expect(listing).not.toContain('my-topic/index.html'));

  it('index.html content has rewritten CSS path', () => {
    const content = execSync(`unzip -p "${tmpZip}" index.html`).toString();
    expect(content).toContain('href="index.css"');
    expect(content).not.toContain('href="../index.css"');
  });

  it('index.html has no <script> tags', () => {
    const content = execSync(`unzip -p "${tmpZip}" index.html`).toString();
    expect(content).not.toContain('<script');
  });

  it('index.html has no explorer sidebar', () => {
    const content = execSync(`unzip -p "${tmpZip}" index.html`).toString();
    expect(content).not.toContain('class="explorer');
  });

  it('within-topic link in sub-page.html is rewritten to ./index.html', () => {
    const content = execSync(`unzip -p "${tmpZip}" sub-page.html`).toString();
    expect(content).toContain('href="./index.html"');
  });
});

